  function corsHeaders() {
    return {
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'GET, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type, Authorization'
    };
  }
  
  function handleFilesRequest(request, username) {
    if (!(username in userFiles)) {
      return new Response('User files not found', { status: 404, headers: corsHeaders() });
    }
  
    const authHeader = request.headers.get('Authorization') || '';
    if (authHeader !== `Bearer ${username}-token`) {
      return new Response('Unauthorized', { status: 401, headers: corsHeaders() });
    }
  
    const files = userFiles[username];
  
    return new Response(JSON.stringify(files), {
      status: 200,
      headers: {
        'Content-Type': 'application/json',
        ...corsHeaders()
      }
    });
  }
  